"""Валидация пользовательских плагинов."""from __future__ import annotationsimport inspectfrom types import ModuleTypefrom typing import Anyfrom ..core.interfaces import IFilter, INoise, ISignalfrom .api import API_VERSION_ALLOWED_PARAM_TYPES = {"int", "float", "bool", "enum"}class PluginError(Exception):    passclass PluginImportError(PluginError):    passclass PluginContractError(PluginError):    passclass PluginAPIVersionError(PluginError):    passdef _validate_params_schema(schema: Any, plugin_name: str) -> None:    if not isinstance(schema, dict) or not schema:        raise PluginContractError(            f"Плагин '{plugin_name}': params_schema должна быть непустым dict"        )    for key, spec in schema.items():        if not isinstance(key, str) or not key.strip():            raise PluginContractError(                f"Плагин '{plugin_name}': ключ параметра должен быть непустой строкой"            )        if not isinstance(spec, dict):            raise PluginContractError(                f"Плагин '{plugin_name}': описание параметра '{key}' должно быть dict"            )        t = spec.get("type")        if t not in _ALLOWED_PARAM_TYPES:            raise PluginContractError(                f"Плагин '{plugin_name}', параметр '{key}': недопустимый 'type'={t!r}"            )        if "default" not in spec:            raise PluginContractError(                f"Плагин '{plugin_name}', параметр '{key}': отсутствует 'default'"            )        if "label" not in spec or not isinstance(spec["label"], str) or not spec["label"]:            raise PluginContractError(                f"Плагин '{plugin_name}', параметр '{key}': отсутствует непустой 'label'"            )        if t in ("int", "float"):            if "min" not in spec or "max" not in spec:                raise PluginContractError(                    f"Плагин '{plugin_name}', параметр '{key}': требуется 'min' и 'max'"                )            if not (isinstance(spec["min"], (int, float))                    and isinstance(spec["max"], (int, float))):                raise PluginContractError(                    f"Плагин '{plugin_name}', параметр '{key}': min/max должны быть числами"                )            if spec["max"] <= spec["min"]:                raise PluginContractError(                    f"Плагин '{plugin_name}', параметр '{key}': max должен быть > min"                )            if not (spec["min"] <= spec["default"] <= spec["max"]):                raise PluginContractError(                    f"Плагин '{plugin_name}', параметр '{key}': default вне [min, max]"                )        if t == "enum":            choices = spec.get("choices")            if not isinstance(choices, (list, tuple)) or not choices:                raise PluginContractError(                    f"Плагин '{plugin_name}', параметр '{key}': enum требует 'choices'"                )            if spec["default"] not in choices:                raise PluginContractError(                    f"Плагин '{plugin_name}', параметр '{key}': default не в choices"                )def _check_method_signature(plugin: Any, method_name: str, plugin_name: str) -> None:    method = getattr(plugin, method_name, None)    if not callable(method):        raise PluginContractError(            f"Плагин '{plugin_name}': метод '{method_name}' отсутствует"        )    try:        sig = inspect.signature(method)    except (TypeError, ValueError) as e:        raise PluginContractError(            f"Плагин '{plugin_name}': не удалось получить сигнатуру '{method_name}' ({e})"        ) from e    for _, p in sig.parameters.items():        if p.kind == inspect.Parameter.VAR_POSITIONAL:            raise PluginContractError(                f"Плагин '{plugin_name}': метод '{method_name}' не должен принимать *args"            )def validate_module(module: ModuleType) -> Any:    mod_name = getattr(module, "__name__", "<unnamed>")    if not hasattr(module, "API_VERSION"):        raise PluginAPIVersionError(            f"Модуль '{mod_name}': отсутствует обязательная константа API_VERSION"        )    api_ver = getattr(module, "API_VERSION")    if not isinstance(api_ver, str):        raise PluginAPIVersionError(            f"Модуль '{mod_name}': API_VERSION должна быть строкой"        )    if api_ver != API_VERSION:        raise PluginAPIVersionError(            f"Модуль '{mod_name}': API_VERSION='{api_ver}' не совпадает с '{API_VERSION}'"        )    if not hasattr(module, "PLUGIN"):        raise PluginContractError(            f"Модуль '{mod_name}': отсутствует обязательный атрибут PLUGIN"        )    plugin = getattr(module, "PLUGIN")    if isinstance(plugin, INoise) and not isinstance(plugin, (ISignal, IFilter)):        raise PluginContractError(            f"Модуль '{mod_name}': пользовательские шумы не поддерживаются"        )    if isinstance(plugin, ISignal):        method_name = "generate"    elif isinstance(plugin, IFilter):        method_name = "apply"    else:        raise PluginContractError(            f"Модуль '{mod_name}': PLUGIN должен быть ISignal или IFilter"        )    name = getattr(plugin, "name", None)    if not isinstance(name, str) or not name.strip():        raise PluginContractError(            f"Модуль '{mod_name}': 'name' должен быть непустой строкой"        )    if len(name) > 80:        raise PluginContractError(            f"Модуль '{mod_name}': 'name' длиннее 80 символов"        )    description = getattr(plugin, "description", None)    if not isinstance(description, str) or not description.strip():        raise PluginContractError(            f"Плагин '{name}': 'description' должен быть непустой строкой"        )    schema = getattr(plugin, "params_schema", None)    _validate_params_schema(schema, name)    _check_method_signature(plugin, method_name, name)    return plugin